// src/pages/CustomerDashboard.jsx

import { useEffect, useState } from "react";

import axios from "axios";

import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const user = JSON.parse(
    localStorage.getItem("user")
  );

  const [workers, setWorkers] =
    useState([]);

  const [requests, setRequests] =
    useState([]);

  const [form, setForm] =
    useState({

      labourId: "",

      labourName: "",

      workType: "",

      location: "",

      date: ""

    });

  useEffect(() => {

    getWorkers();

    getRequests();

  }, []);

  const getWorkers = async () => {

    const res = await axios.get(

      "http://localhost:5000/api/auth/workers"

    );

    setWorkers(res.data);
  };

  const getRequests = async () => {

    const res = await axios.get(

      `http://localhost:5000/api/request/customer/${user.name}`

    );

    setRequests(res.data);
  };

  const sendRequest = async () => {

    if (
      !form.labourId ||
      !form.location ||
      !form.date
    ) {

      return alert("Fill all fields");

    }

    await axios.post(

      "http://localhost:5000/api/request/send",

      {

        customerName: user.name,

        customerId: user._id,

        labourId: form.labourId,

        labourName: form.labourName,

        workType: form.workType,

        location: form.location,

        date: form.date,

        timings: ["9AM-12PM"]

      }

    );

    alert("Request Sent");

    getRequests();
  };

  const customerDecision =
    async (id, decision) => {

      await axios.put(

        `http://localhost:5000/api/request/customer-decision/${id}`,

        { decision }

      );

      getRequests();
    };

  const submitFeedback =
    async (id) => {

      const rating =
        prompt("Enter Rating (1-5)");

      const comment =
        prompt("Enter Review");

      await axios.put(

        `http://localhost:5000/api/request/feedback/${id}`,

        {
          rating,
          comment
        }

      );

      alert("Feedback Added");

      getRequests();
    };

  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        <div style={styles.card}>

          <h2 style={styles.heading}>
            Find Workers
          </h2>

          <select
            style={styles.input}

            onChange={(e) => {

              const worker =
                workers.find(
                  (w) =>
                    w._id === e.target.value
                );

              setForm({

                ...form,

                labourId: worker._id,

                labourName: worker.name,

                workType:
                  worker.skills[0]

              });
            }}
          >

            <option>
              Select Worker
            </option>

            {workers.map((worker) => (

              <option
                key={worker._id}
                value={worker._id}
              >

                {worker.name}
                {" - "}
                {worker.skills.join(", ")}

              </option>

            ))}

          </select>

          <input
            style={styles.input}
            placeholder="Location"
            onChange={(e) =>
              setForm({
                ...form,
                location:
                  e.target.value
              })
            }
          />

          <input
            type="date"
            style={styles.input}
            onChange={(e) =>
              setForm({
                ...form,
                date: e.target.value
              })
            }
          />

          <button
            style={styles.button}
            onClick={sendRequest}
          >
            Send Request
          </button>

        </div>

        <div style={styles.card}>

          <h2 style={styles.heading}>
            My Requests
          </h2>

          {requests.map((req) => (

            <div
              key={req._id}
              style={styles.requestBox}
            >

              <h3>
                {req.labourName}
              </h3>

              <p>
                Work:
                {" "}
                {req.workType}
              </p>

              <p>
                Date:
                {" "}
                {req.date}
              </p>

              <p>
                Status:
                {" "}
                {req.status}
              </p>

              <p>
                Labour Response:
                {" "}
                {req.labourResponse}
              </p>

              <p>
                Price:
                {" "}
                ₹{req.labourPrice}
              </p>

              <p>
                Customer Decision:
                {" "}
                {req.customerDecision}
              </p>

              {req.labourResponse ===
                "Accepted" &&

                req.customerDecision ===
                  "Waiting" && (

                <div
                  style={styles.btnRow}
                >

                  <button
                    style={
                      styles.acceptBtn
                    }

                    onClick={() =>
                      customerDecision(
                        req._id,
                        "Accepted"
                      )
                    }
                  >
                    Accept
                  </button>

                  <button
                    style={
                      styles.rejectBtn
                    }

                    onClick={() =>
                      customerDecision(
                        req._id,
                        "Rejected"
                      )
                    }
                  >
                    Reject
                  </button>

                </div>

              )}

              {req.customerDecision ===
                "Accepted" && (

                <button
                  style={styles.feedbackBtn}
                  onClick={() =>
                    submitFeedback(
                      req._id
                    )
                  }
                >
                  Give Rating & Review
                </button>

              )}

            </div>

          ))}

        </div>

      </div>

    </div>
  );
}

const styles = {

  page: {
    background: "#f4f7fb",
    minHeight: "100vh"
  },

  container: {
    padding: "30px",
    display: "grid",
    gridTemplateColumns:
      "1fr 1fr",
    gap: "25px"
  },

  card: {
    background: "white",
    padding: "25px",
    borderRadius: "16px",
    boxShadow:
      "0 4px 12px rgba(0,0,0,0.05)"
  },

  heading: {
    marginBottom: "20px"
  },

  input: {
    width: "100%",
    padding: "14px",
    marginBottom: "16px",
    borderRadius: "10px",
    border: "1px solid #d1d5db",
    boxSizing: "border-box"
  },

  button: {
    width: "100%",
    padding: "14px",
    background: "#2563eb",
    color: "white",
    border: "none",
    borderRadius: "10px",
    cursor: "pointer"
  },

  requestBox: {
    border: "1px solid #e5e7eb",
    borderRadius: "12px",
    padding: "16px",
    marginBottom: "18px"
  },

  btnRow: {
    display: "flex",
    gap: "10px",
    marginTop: "10px"
  },

  acceptBtn: {
    flex: 1,
    padding: "10px",
    background: "green",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer"
  },

  rejectBtn: {
    flex: 1,
    padding: "10px",
    background: "red",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer"
  },

  feedbackBtn: {
    marginTop: "10px",
    width: "100%",
    padding: "12px",
    background: "#111827",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer"
  }

};
